sys_script_client.script:
function onSubmit() {

	//created by : Sandesh Bhale , Created on : 22-07-2026 , Purpose : onSubmit validation

    var cost = g_form.getValue('estimated_cost');
    var assetType = g_form.getValue('asset_type');

    if ((cost.endsWith(';0.00') || cost == '') && assetType != 'software' ) {
        g_form.addErrorMessage('Estimated cost should not be empty or 0 for asset type of hardware !');
        return false;
    }

}
